funcs.test_tablefmt_variants_produce_nonempty_:
def test_tablefmt_variants_produce_nonempty_strings_s3():
    data = [["a", 1], ["b", 2]]
    formats = [
        "plain", "simple", "grid", "pipe", "rst", "mediawiki", "html", "latex",
        "pretty", "tsv"
    ]
    for fmt in formats:
        out = tabulate(data, tablefmt=fmt)
        assert isinstance(out, str)
        assert len(out) > 0
        # For tsv, tabs should be present
        if fmt == "tsv":
            assert "\t" in out
